<?php
require_once __DIR__ . '/store.php';
require_once __DIR__ . '/payment_gateway.php';
require_once __DIR__ . '/revenue_access_governance.php';
function sf_store_checkout_runtime_ready(): bool{return sf_payment_provider()==='sandbox'&&sf_revenue_sandbox_allowed('merch');}
function sf_store_create_order_secure(array $customer): ?array{if(!sf_store_checkout_runtime_ready()){sf_store_flash('error','Merch checkout is disabled until a verified live payment adapter is configured.');return null;}if(!sf_store_db_ready()){if(sf_revenue_is_production()){sf_store_flash('error','Database-backed checkout is required in production.');return null;}return sf_store_create_order($customer);}$pdo=sf_db();$cartId=sf_store_current_cart_id(false);if(!$pdo||!$cartId){sf_store_flash('error','Cart could not be found.');return null;}try{$pdo->beginTransaction();$lock=$pdo->prepare("SELECT id FROM carts WHERE id=? AND status='active' FOR UPDATE");$lock->execute([$cartId]);if(!$lock->fetch())throw new RuntimeException('Cart is no longer active.');$rows=$pdo->prepare("SELECT ci.product_id,ci.variant_id,ci.quantity,p.name product_name,p.slug product_slug,p.product_type,p.access_level,p.price_cents product_price,p.inventory_quantity product_inventory,p.status product_status,pv.variant_name,pv.price_cents variant_price,pv.inventory_quantity variant_inventory,pv.status variant_status FROM cart_items ci INNER JOIN products p ON p.id=ci.product_id LEFT JOIN product_variants pv ON pv.id=ci.variant_id WHERE ci.cart_id=? ORDER BY ci.id FOR UPDATE");$rows->execute([$cartId]);$items=[];foreach($rows->fetchAll()?:[]as$row){$qty=max(1,min(99,(int)$row['quantity']));$product=['id'=>(int)$row['product_id'],'access_level'=>$row['access_level'],'status'=>$row['product_status']];if(($row['product_status']??'')!=='active'||!sf_store_can_purchase($product))throw new RuntimeException('One item is no longer available.');$variantId=!empty($row['variant_id'])?(int)$row['variant_id']:null;$available=$variantId?(int)$row['variant_inventory']:(int)$row['product_inventory'];if($variantId&&($row['variant_status']??'')!=='active')throw new RuntimeException('One selected option is no longer available.');if($available<$qty)throw new RuntimeException(($row['product_name']??'Item').' only has '.max(0,$available).' available.');$unit=$variantId&&$row['variant_price']!==null?(int)$row['variant_price']:(int)$row['product_price'];if($unit<=0)throw new RuntimeException('One item has an invalid price.');$items[]=['product_id'=>(int)$row['product_id'],'variant_id'=>$variantId,'product_name'=>(string)$row['product_name'],'product_slug'=>(string)$row['product_slug'],'variant_name'=>(string)($row['variant_name']??'Standard'),'quantity'=>$qty,'unit_price_cents'=>$unit,'product_type'=>(string)($row['product_type']??'physical')];}$totals=sf_store_cart_totals($items);$errors=sf_store_validate_checkout($customer,$items,$totals);if($errors)throw new RuntimeException(implode(' ',$errors));$number=sf_store_next_order_number();$receipt=bin2hex(random_bytes(32));$payment='sandbox_merch_'.substr(hash('sha256',$number.'|'.sf_session_key()),0,24);$columns=['user_id','order_number','status','subtotal_cents','shipping_cents','tax_cents','total_cents','customer_email','shipping_name','shipping_address_1','shipping_address_2','shipping_city','shipping_state','shipping_postal_code','shipping_country','external_payment_id'];$values=[sf_current_user_id(),$number,'paid',$totals['subtotal_cents'],$totals['shipping_cents'],$totals['tax_cents'],$totals['total_cents'],$customer['email'],$customer['name'],$customer['address_1'],$customer['address_2'],$customer['city'],$customer['state'],$customer['postal_code'],$customer['country'],$payment];foreach(['receipt_token'=>$receipt,'payment_status'=>'paid','fulfillment_status'=>'unfulfilled','customer_phone'=>$customer['phone'],'shipping_method'=>'standard','notes'=>$customer['notes']]as$column=>$value)if(sf_store_column_exists('orders',$column)){$columns[]=$column;$values[]=$value;}$stmt=$pdo->prepare('INSERT INTO orders (`'.implode('`,`',$columns).'`) VALUES ('.implode(',',array_fill(0,count($columns),'?')).')');$stmt->execute($values);$orderId=(int)$pdo->lastInsertId();$itemInsert=$pdo->prepare('INSERT INTO order_items (order_id,product_id,variant_id,product_name,variant_name,quantity,unit_price_cents,total_price_cents) VALUES (?,?,?,?,?,?,?,?)');foreach($items as$item){$qty=(int)$item['quantity'];$variantId=$item['variant_id'];$itemInsert->execute([$orderId,$item['product_id'],$variantId,$item['product_name'],$item['variant_name'],$qty,$item['unit_price_cents'],$qty*$item['unit_price_cents']]);if($variantId){$dec=$pdo->prepare("UPDATE product_variants SET inventory_quantity=inventory_quantity-?,updated_at=NOW() WHERE id=? AND status='active' AND inventory_quantity>=?");$dec->execute([$qty,$variantId,$qty]);}else{$dec=$pdo->prepare("UPDATE products SET inventory_quantity=inventory_quantity-?,updated_at=NOW() WHERE id=? AND status='active' AND inventory_quantity>=?");$dec->execute([$qty,$item['product_id'],$qty]);}if($dec->rowCount()!==1)throw new RuntimeException('Inventory changed during checkout. Please review your cart.');sf_store_record_inventory_movement($pdo,$item['product_id'],$variantId,$orderId,-$qty,'sandbox_order_paid');}$pdo->prepare("UPDATE carts SET status='converted',updated_at=NOW() WHERE id=? AND status='active'")->execute([$cartId]);if(sf_store_table_exists('payment_transactions')){$pay=$pdo->prepare("INSERT INTO payment_transactions (user_id,order_id,provider,provider_payment_id,transaction_type,status,amount_cents,currency,raw_payload_json) VALUES (?,?,'sandbox',?,'merch_order','paid',?,'USD',?)");$pay->execute([sf_current_user_id(),$orderId,$payment,$totals['total_cents'],json_encode(['mode'=>'sandbox','verified'=>true,'order_number'=>$number],JSON_UNESCAPED_SLASHES)]);}sf_store_insert_order_history($pdo,$orderId,'','paid','Verified local sandbox checkout completed.');$pdo->commit();$order=sf_store_order_by_number($number,$receipt)?:['order_number'=>$number,'receipt_token'=>$receipt];$_SESSION[SF_STORE_SESSION_LAST_ORDER]=['order_number'=>$number,'receipt_token'=>$receipt];sf_store_send_order_notifications($order);return$order;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log('Stonefellow secure order create failed: '.$e->getMessage());sf_store_flash('error',$e->getMessage());return null;}}
function sf_store_order_lookup_authorized(string $number,string $receipt=''): ?array{$number=trim($number);$receipt=trim($receipt);if($number==='')return null;if(!sf_store_db_ready())return sf_store_order_by_number($number,$receipt);try{$stmt=sf_db()->prepare('SELECT * FROM orders WHERE order_number=? LIMIT 1');$stmt->execute([$number]);$order=$stmt->fetch();if(!$order)return null;$owner=sf_current_user_id()>0&&(int)($order['user_id']??0)===sf_current_user_id();$stored=(string)($order['receipt_token']??'');$keyOk=$stored!==''&&$receipt!==''&&hash_equals($stored,$receipt);if(!$owner&&!$keyOk)return null;$order['items']=sf_store_order_items((int)$order['id']);return$order;}catch(Throwable$e){return null;}}
?>